{
    "level": "B1",
    "intro": "In this topic, you will learn the <strong>passive state in key tenses</strong>: Continuous, Perfect, and Future.",
    "rules": [
        {
            "label": "Continuous",
            "color": "emerald",
            "text": "<strong>be + being + V3</strong> — action in process:",
            "example": "The house is being painted."
        },
        {
            "label": "Perfect",
            "color": "blue",
            "text": "<strong>have/had + been + V3</strong> - completed action:",
            "example": "The letter has been sent."
        },
        {
            "label": "Future",
            "color": "rose",
            "text": "<strong>will + be + V3</strong> — future action:",
            "example": "The work will be done."
        }
    ]
}

{
    "title": "1. Present Continuous Passive — is being done",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "Formula: <strong>am/is/are + being + Past Participle (V3)</strong>",
            "examples": [
                {
                    "en": "The house is being painted right now.",
                    "ua": "The house is being painted right now."
                },
                {
                    "en": "The documents are being prepared at the moment.",
                    "ua": "The documents are being prepared at the moment."
                },
                {
                    "en": "I am being interviewed for a new position.",
                    "ua": "I am being interviewed for a new position."
                }
            ]
        },
        {
            "label": "Using",
            "color": "sky",
            "description": "The action <strong>happens now</strong>, in progress. Prolonged action in the passive state.",
            "examples": [
                {
                    "en": "The road is being repaired this week.",
                    "ua": "The road is being repaired this week."
                },
                {
                    "en": "New software is being installed on all computers.",
                    "ua": "New software is being installed on all computers."
                }
            ]
        },
        {
            "label": "Objections and questions",
            "color": "amber",
            "description": "Neg: <strong>am/is/are + not + being + V3</strong>. Q: <strong>Am/Is/Are + S + being + V3?</strong>",
            "examples": [
                {
                    "en": "The house is not being painted today.",
                    "ua": "The house is not being painted today."
                },
                {
                    "en": "Is the project being worked on?",
                    "ua": "Is the project being worked on?"
                }
            ]
        }
    ]
}

{
    "title": "2. Past Continuous Passive — was being done",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "Formula: <strong>was/were + being + Past Participle (V3)</strong>",
            "examples": [
                {
                    "en": "The car was being repaired when I arrived.",
                    "ua": "The car was being repaired when I arrived."
                },
                {
                    "en": "The rooms were being cleaned all morning.",
                    "ua": "The rooms were being cleaned all morning."
                },
                {
                    "en": "I was being examined by the doctor.",
                    "ua": "I was being examined by the doctor."
                }
            ]
        },
        {
            "label": "Using",
            "color": "sky",
            "description": "The action <strong>continued in the past</strong> at a certain moment. The process that took place.",
            "examples": [
                {
                    "en": "While I was waiting, my application was being processed.",
                    "ua": "While I was waiting, my application was being processed."
                },
                {
                    "en": "The building was being constructed last year.",
                    "ua": "The building was being constructed last year."
                }
            ]
        },
        {
            "label": "Objections and questions",
            "color": "amber",
            "description": "Neg: <strong>was/were + not + being + V3</strong>. Q: <strong>Was/Were + S + being + V3?</strong>",
            "examples": [
                {
                    "en": "The issue was not being discussed then.",
                    "ua": "The issue was not being discussed then."
                },
                {
                    "en": "Were the emails being sent?",
                    "ua": "Were the emails being sent?"
                }
            ]
        }
    ]
}

{
    "title": "3. Present Perfect Passive — has been done",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "Formula: <strong>has/have + been + Past Participle (V3)</strong>",
            "examples": [
                {
                    "en": "The project has been completed successfully.",
                    "ua": "The project has been completed successfully."
                },
                {
                    "en": "All the tickets have been sold already.",
                    "ua": "All the tickets have been sold already."
                },
                {
                    "en": "I have been promoted to manager!",
                    "ua": "I have been promoted to manager!"
                }
            ]
        },
        {
            "label": "Using",
            "color": "sky",
            "description": "The action is <strong>finished</strong> and the result is important now. Connection with the present.",
            "examples": [
                {
                    "en": "The report has just been submitted.",
                    "ua": "The report has just been submitted."
                },
                {
                    "en": "The files have already been deleted.",
                    "ua": "The files have already been deleted."
                },
                {
                    "en": "The work has been done perfectly.",
                    "ua": "The work has been done perfectly."
                }
            ]
        },
        {
            "label": "Time markers",
            "color": "amber",
            "description": "Typical words: <strong>just, already, yet, recently, ever, never, since, for</strong>",
            "examples": [
                {
                    "en": "The email has not been sent yet.",
                    "ua": "The email has not been sent yet."
                },
                {
                    "en": "Have you ever been interviewed?",
                    "ua": "Have you ever been interviewed?"
                }
            ]
        }
    ]
}

{
    "title": "4. Past Perfect Passive — had been done",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "Formula: <strong>had + been + Past Participle (V3)</strong>",
            "examples": [
                {
                    "en": "The work had been finished before the deadline.",
                    "ua": "The work had been finished before the deadline."
                },
                {
                    "en": "The tickets had been sold out before we arrived.",
                    "ua": "The tickets had been sold out before we arrived."
                },
                {
                    "en": "The documents had been signed earlier.",
                    "ua": "The documents had been signed earlier."
                }
            ]
        },
        {
            "label": "Using",
            "color": "sky",
            "description": "An action was completed <strong>before another past action</strong> or moment.",
            "examples": [
                {
                    "en": "By the time I got there, the problem had been solved.",
                    "ua": "By the time I got there, the problem had been solved."
                },
                {
                    "en": "The email had been deleted before I could read it.",
                    "ua": "The email had been deleted before I could read it."
                }
            ]
        },
        {
            "label": "Objections and questions",
            "color": "amber",
            "description": "Neg: <strong>had + not + been + V3</strong>. Q: <strong>Had + S + been + V3?</strong>",
            "examples": [
                {
                    "en": "The work had not been completed by then.",
                    "ua": "The work had not been completed by then."
                },
                {
                    "en": "Had the letter been sent?",
                    "ua": "Had the letter been sent?"
                }
            ]
        }
    ]
}

{
    "title": "5. Future Simple Passive — will be done",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "Formula: <strong>will + be + Past Participle (V3)</strong>",
            "examples": [
                {
                    "en": "The results will be announced tomorrow.",
                    "ua": "The results will be announced tomorrow."
                },
                {
                    "en": "The meeting will be held next Monday.",
                    "ua": "The meeting will be held next Monday."
                },
                {
                    "en": "You will be contacted soon.",
                    "ua": "You will be contacted soon."
                }
            ]
        },
        {
            "label": "Using",
            "color": "sky",
            "description": "The action <strong>will take place in the future</strong>. Plan, forecast, promise in the passive voice.",
            "examples": [
                {
                    "en": "The work will be done by Friday.",
                    "ua": "The work will be done by Friday."
                },
                {
                    "en": "A new office will be opened next year.",
                    "ua": "A new office will be opened next year."
                }
            ]
        },
        {
            "label": "Objections and questions",
            "color": "amber",
            "description": "Neg: <strong>will not (won't) + be + V3</strong>. Q: <strong>Will + S + be + V3?</strong>",
            "examples": [
                {
                    "en": "The project will not be finished on time.",
                    "ua": "The project will not be finished on time."
                },
                {
                    "en": "Will the report be ready by Friday?",
                    "ua": "Will the report be ready by Friday?"
                }
            ]
        }
    ]
}

{
    "title": "6. Future Perfect Passive — will have been done",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "Formula: <strong>will have + been + Past Participle (V3)</strong>. Rarely used.",
            "examples": [
                {
                    "en": "The work will have been completed by next week.",
                    "ua": "The work will have been completed by next week."
                },
                {
                    "en": "By tomorrow, the report will have been submitted.",
                    "ua": "By tomorrow, the report will have been submitted."
                }
            ]
        },
        {
            "label": "Using",
            "color": "sky",
            "description": "The action <strong>will be completed by some point in the future</strong>. It is rare.",
            "examples": [
                {
                    "en": "By 6 PM, all emails will have been sent.",
                    "ua": "By 6 PM, all emails will have been sent."
                }
            ]
        }
    ]
}

{
    "title": "7. Summary table of all tenses in the passive",
    "intro": "Structures of the passive state in all main tenses:",
    "rows": [
        {
            "en": "Present Simple",
            "ua": "Present Simple",
            "note": "The letter is written."
        },
        {
            "en": "Past Simple",
            "ua": "Past Simple",
            "note": "The letter was written."
        },
        {
            "en": "Present Continuous",
            "ua": "Present Continuous",
            "note": "The letter is being written."
        },
        {
            "en": "Past Continuous",
            "ua": "Past Continuous",
            "note": "The letter was being written."
        },
        {
            "en": "Present Perfect",
            "ua": "Present Perfect",
            "note": "The letter has been written."
        },
        {
            "en": "Past Perfect",
            "ua": "Past Perfect",
            "note": "The letter had been written."
        },
        {
            "en": "Future Simple",
            "ua": "Future Simple",
            "note": "The letter will be written."
        },
        {
            "en": "Future Perfect",
            "ua": "Future Perfect",
            "note": "The letter will have been written."
        }
    ]
}

{
    "title": "8. Which tenses do not have a passive voice?",
    "sections": [
        {
            "label": "There is no Continuous Perfect",
            "color": "rose",
            "description": "The <strong>Present Perfect Continuous</strong> and other Perfect Continuouss do not have a passive form.",
            "examples": [
                {
                    "en": "❌ The letter has been being written. (немає такої форми)",
                    "ua": "❌ The letter has been being written. (немає такої форми)"
                }
            ]
        },
        {
            "label": "Rare: Future Continuous",
            "color": "amber",
            "description": "<strong>Future Continuous Passive</strong> theoretically exists, but is very rarely used.",
            "examples": [
                {
                    "en": "The house will be being painted. (рідко)",
                    "ua": "The house will be being painted. (рідко)"
                }
            ]
        }
    ]
}

{
    "title": "9. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Confusion with being in Continuous.",
            "wrong": "The house is painted now.",
            "right": "✅ The house is being painted now."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Skip been in Perfect.",
            "wrong": "The work has completed.",
            "right": "✅ The work has been completed."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Wrong order in Future.",
            "wrong": "It be will done.",
            "right": "✅ It will be done."
        }
    ]
}
